            "ori        %[sign1],   $zero,      0               \n\t"

            "ori        %[sign2],   $zero,      0               \n\t"

            "slt        %[t0],      %[t4],      %[qc1]          \n\t"

            "slt        %[t1],      %[t4],      %[qc2]          \n\t"

            "slt        %[t2],      %[t4],      %[qc3]          \n\t"

            "slt        %[t3],      %[t4],      %[qc4]          \n\t"

