            "movn       %[sign2],   %[t2],      %[qc3]          \n\t"

            "slt        %[t1],      %[t1],      $zero           \n\t"

            "sll        %[t0],      %[sign1],   1               \n\t"

            "or         %[t0],      %[t0],      %[t1]           \n\t"

            "movn       %[sign1],   %[t0],      %[qc2]          \n\t"

            "slt        %[t3],      %[t3],      $zero           \n\t"

            "sll        %[t0],      %[sign2],   1               \n\t"

