            "lwc1       %[di0],     0(%[in_pos])                \n\t"

            "lwc1       %[di1],     4(%[in_pos])                \n\t"

            "lwc1       %[di2],     8(%[in_pos])                \n\t"

            "lwc1       %[di3],     12(%[in_pos])               \n\t"

            "abs.s      %[di0],     %[di0]                      \n\t"

            "abs.s      %[di1],     %[di1]                      \n\t"

            "abs.s      %[di2],     %[di2]                      \n\t"

            "abs.s      %[di3],     %[di3]                      \n\t"

            "lwc1       $f0,        0(%[vec])                   \n\t"

            "lwc1       $f1,        4(%[vec])                   \n\t"

            "lwc1       $f2,        0(%[vec2])                  \n\t"

            "lwc1       $f3,        4(%[vec2])                  \n\t"

            "nmsub.s    %[di0],     %[di0],     $f0,    %[IQ]   \n\t"

            "nmsub.s    %[di1],     %[di1],     $f1,    %[IQ]   \n\t"

            "nmsub.s    %[di2],     %[di2],     $f2,    %[IQ]   \n\t"

            "nmsub.s    %[di3],     %[di3],     $f3,    %[IQ]   \n\t"



            ".set pop                                           \n\t"



            : [di0]"=&f"(di0), [di1]"=&f"(di1),

              [di2]"=&f"(di2), [di3]"=&f"(di3)

            : [in_pos]"r"(in_pos), [vec]"r"(vec),

              [vec2]"r"(vec2), [IQ]"f"(IQ)

            : "$f0", "$f1", "$f2", "$f3",

